try:
    with table.batch_writer() as batch:
        for zone in zones:
            entity_id = f"ZONE#{zone['Name'].upper().replace(' ', '_')}"
            batch.put_item(Item={
                'EntityId': entity_id,
                'Type': 'Zone',
                'ZoneName': zone['Name'],
                'ZoneType': zone['Type'],
                'Coordinates': float_to_decimal(zone['Coords'])
            })
    print("Upload complete!")
except Exception as e:
    print(f"Error during upload: {e}")